for i,l in enumerate(lines,1):
    for m in re.finditer(r'\\(begin|end)\{(\w+)\}',l):
        kind,env=m.group(1),m.group(2)
        if kind=='begin': stack.append((env,i))
        else:
            if stack and stack[-1][0]==env: stack.pop()
            else: print(f"MISMATCH at line {i}: end{{{env}}}, stack top={stack[-1] if stack else None}")
print("UNCLOSED:",stack[-5:] if stack else "none")
